<?php
namespace Tests\Feature;use App\Domain\GameHome\Media\GameHomeCardBannerException;use App\Domain\GameHome\Media\GameHomeCardBannerService;use App\Domain\Media\MediaAssetType;use App\Models\GameHomeCard;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Http\UploadedFile;use Illuminate\Support\Facades\Storage;use Tests\TestCase;
class GameHomeCardBannerTest extends TestCase{use RefreshDatabase;private function card(){return GameHomeCard::create(['name'=>'Banner','code'=>'banner-'.uniqid(),'destination_type'=>'route','destination_value'=>'world-maps.index','sort_order'=>1,'is_active'=>true,'opens_new_tab'=>false]);}private function image($format='png',$width=1200,$height=400){$path=tempnam(sys_get_temp_dir(),'home_');$image=imagecreatetruecolor($width,$height);imagefill($image,0,0,imagecolorallocate($image,30,60,90));if($format==='jpeg')imagejpeg($image,$path);elseif($format==='webp')imagewebp($image,$path);else imagepng($image,$path);imagedestroy($image);$mime=$format==='jpeg'?'image/jpeg':'image/'.$format;return new UploadedFile($path,'banner.'.$format,$mime,null,true);}public function test_png_jpeg_and_webp_are_valid_original_banners(){Storage::fake('public');$service=app(GameHomeCardBannerService::class);foreach(['png','jpeg','webp']as$format){$card=$this->card();$asset=$service->replace($card,$this->image($format));$this->assertSame(MediaAssetType::HOME_CARD_BANNER,$asset->asset_type);$this->assertSame(1200,$asset->width);$this->assertSame(400,$asset->height);Storage::disk('public')->assertExists($asset->path);}}public function test_replace_and_delete_are_scoped_and_invalid_dimensions_fail(){Storage::fake('public');$card=$this->card();$service=app(GameHomeCardBannerService::class);$first=$service->replace($card,$this->image());$second=$service->replace($card,$this->image('jpeg'));$this->assertDatabaseMissing('media_assets',['id'=>$first->id]);Storage::disk('public')->assertMissing($first->path);$service->delete($card);$this->assertDatabaseHas('game_home_cards',['id'=>$card->id]);$this->assertDatabaseMissing('media_assets',['id'=>$second->id]);try{$service->replace($card,$this->image('png',600,200));$this->fail();}catch(GameHomeCardBannerException $e){$this->assertTrue(true);}}}
